t.script:
document.addEventListener('DOMContentLoaded', function () {
    var deptSelect = document.getElementById('department_select');
    var docSelect = document.getElementById('doctor_select');
    var dateInput = document.getElementById('appointment_date');
    var slotSection = document.getElementById('time_slot_section');
    var slotItems = document.querySelectorAll('.slot-item');

    function refreshAvailableSlots() {
        var chosenDoctor = docSelect.value;
        var chosenDate = dateInput.value;

        if (chosenDoctor && chosenDate) {
            var visibleCount = 0;
            slotItems.forEach(function (item) {
                var slotDoc = item.getAttribute('data-doctor-id');
                var slotDate = item.getAttribute('data-date');

                if (slotDoc === chosenDoctor && slotDate === chosenDate) {
                    item.classList.remove('d-none');
                    visibleCount++;
                } else {
                    item.classList.add('d-none');
                    var inputElement = item.querySelector('input');
                    if (inputElement) {
                        inputElement.checked = false;
                    }
                }
            });

            if (visibleCount > 0) {
                slotSection.classList.remove('d-none');
            } else {
                slotSection.classList.add('d-none');
            }
        } else {
            slotSection.classList.add('d-none');
        }
    }

    if (docSelect) docSelect.addEventListener('change', refreshAvailableSlots);
    if (dateInput) dateInput.addEventListener('change', refreshAvailableSlots);

    if (deptSelect) {
        deptSelect.addEventListener('change', function () {
            var deptId = deptSelect.value;
            if (!docSelect) return;

            docSelect.innerHTML = '<option value="">Loading...</option>';

            if (!deptId) {
                docSelect.innerHTML = '<option value="">Select Department First</option>';
                refreshAvailableSlots();
                return;
            }

            fetch('/get_doctors', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ jsonrpc: "2.0", params: { department_id: deptId } })
            })
            .then(function (response) { return response.json(); })
            .then(function (data) {
                var doctors = data.result;
                docSelect.innerHTML = '<option value="">Select Doctor</option>';
                if (!doctors || doctors.length === 0) {
                    docSelect.innerHTML = '<option value="">No doctors in this department</option>';
                    refreshAvailableSlots();
                    return;
                }
                doctors.forEach(function (doc) {
                    var opt = document.createElement('option');
                    opt.value = doc.id;
                    opt.textContent = doc.name;
                    docSelect.appendChild(opt);
                });
                refreshAvailableSlots();
            });
        });
    }

    // Medical report visibility control checkbox
    var checkbox = document.getElementById('has_previous_report');
    var uploadSection = document.getElementById('report_upload_section');
    if (checkbox && uploadSection) {
        checkbox.addEventListener('change', function () {
            uploadSection.style.display = checkbox.checked ? 'block' : 'none';
        });
    }
});
